"use client";

import { ArrowDownLeft, ArrowRight, Bell, CalendarClock, Check, CreditCard, FileText, LayoutDashboard, Menu, Moon, Plus, ReceiptText, Settings, Sun, Trees, WalletCards, X } from "lucide-react";
import { useEffect, useMemo, useState } from "react";

type Theme = "dark" | "forest" | "light";
type Tab = "overview" | "bills" | "upcoming" | "balances" | "activity";
type ModalName = "bill" | "edit" | "payment" | "recurring-edit" | "detail" | "settings" | null;
type User = { id: string; email: string; displayName: string; role: "member" | "administrator" };
type HouseholdListItem = { id: string; name: string; currency: string };
type Member = { id: string; displayName: string; email: string };
type Bill = { id: string; name: string; amountCents: number; periodLabel: string; dueDate?: string | null; amountState: "estimated" | "final"; status: "draft" | "open" | "settled" | "void"; createdByName?: string; createdAt: string };
type Balance = { payerUserId: string; recipientUserId: string; payerName?: string; recipientName?: string; amountCents: number };
type Payment = { id: string; billId?: string | null; payerUserId: string; recipientUserId: string; payerName?: string; recipientName?: string; actorName?: string; billName?: string | null; amountCents: number; note?: string | null; paidAt: string };
type Closure = { id: string; billId: string; billName: string; actorName: string; changedAt: string };
type Recurring = { id: string; name: string; expectedAmountCents: number | null; cadence: "weekly" | "monthly" | "quarterly" | "yearly"; nextOccurrence: string; allocationMethod: "equal" | "percentage" | "fixed"; templateConfig: { contributions: Array<{ userId: string; amountCents: number }>; allocations: Array<{ userId: string; amountCents: number; percentageBasisPoints?: number }> }; active: boolean };
type HouseholdData = { household: HouseholdListItem & { timezone: string }; members: Member[]; bills: Bill[]; balances: Balance[]; payments: Payment[]; closures: Closure[]; recurring: Recurring[] };
type SessionData = { user: User; csrfToken: string; households: HouseholdListItem[] };
type NotificationItem = { id: string; title: string; body: string; readAt: string | null; createdAt: string };
type NotificationPrefs = { billsEnabled: boolean; paymentsEnabled: boolean; balanceChangesEnabled: boolean };
type BillDetailData = { bill: Bill & { revision: number; allocationMethod: string }; contributions: Array<{ id: string; userId: string; displayName: string; amountCents: number; paidAt: string }>; allocations: Array<{ id: string; userId: string; displayName: string; amountCents: number; percentageBasisPoints: number | null }>; obligations: Array<{ id: string; debtorUserId: string; creditorUserId: string; debtorName: string; creditorName: string; originalAmountCents: number; paidAmountCents: number; outstandingAmountCents: number }>; payments: Payment[]; history: Array<{ id: string; changeType: string; changedBy: string; changedAt: string }> };

const money = (cents: number, currency = "USD") => new Intl.NumberFormat(undefined, { style: "currency", currency }).format(cents / 100);
const initials = (name: string) => name.split(/\s+/).map((part) => part[0]).join("").slice(0, 2).toUpperCase();

export function HouseholdApp() {
  const [session, setSession] = useState<SessionData | null>(null);
  const [householdId, setHouseholdId] = useState("");
  const [data, setData] = useState<HouseholdData | null>(null);
  const [tab, setTab] = useState<Tab>("overview");
  const [modal, setModal] = useState<ModalName>(null);
  const [theme, setTheme] = useState<Theme>("dark");
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notificationsOpen, setNotificationsOpen] = useState(false);
  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
  const [toast, setToast] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [installPrompt, setInstallPrompt] = useState<Event | null>(null);
  const [billDetail, setBillDetail] = useState<BillDetailData | null>(null);
  const [paymentContext, setPaymentContext] = useState<(Balance & { billId: string }) | null>(null);
  const [selectedRecurring, setSelectedRecurring] = useState<Recurring | null>(null);
  const [preferences, setPreferences] = useState<NotificationPrefs>({ billsEnabled: true, paymentsEnabled: true, balanceChangesEnabled: true });
  const [vapidPublicKey, setVapidPublicKey] = useState<string | null>(null);

  useEffect(() => {
    document.documentElement.dataset.theme = "dark";
    Promise.all([fetch("/api/session", { cache: "no-store" }), fetch("/api/settings", { cache: "no-store" })]).then(async ([sessionResponse, settingsResponse]) => {
      if (sessionResponse.status === 401) { location.href = "/login"; return; }
      const sessionData = await sessionResponse.json() as SessionData;
      const settings = settingsResponse.ok ? await settingsResponse.json() : null;
      setSession(sessionData);
      const savedTheme: Theme = settings?.account?.themePreference === "light" || settings?.account?.themePreference === "forest" ? settings.account.themePreference : "dark";
      setTheme(savedTheme); document.documentElement.dataset.theme = savedTheme;
      if (settings?.notifications) setPreferences({ billsEnabled: settings.notifications.billsEnabled, paymentsEnabled: settings.notifications.paymentsEnabled, balanceChangesEnabled: settings.notifications.balanceChangesEnabled });
      setVapidPublicKey(settings?.vapidPublicKey ?? null);
      const savedHousehold = localStorage.getItem("fairshare-household");
      setHouseholdId(sessionData.households.some((item) => item.id === savedHousehold) ? savedHousehold! : sessionData.households[0]?.id ?? "");
      if (!sessionData.households.length) setLoading(false);
    }).catch(() => { setError("FairShare could not load your account."); setLoading(false); });
    const onInstall = (event: Event) => { event.preventDefault(); setInstallPrompt(event); };
    window.addEventListener("beforeinstallprompt", onInstall);
    return () => window.removeEventListener("beforeinstallprompt", onInstall);
  }, []);

  // refresh is intentionally keyed only by the selected Household.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { if (householdId) void refresh(); }, [householdId]);
  useEffect(() => { if (!toast) return; const timer = setTimeout(() => setToast(""), 3200); return () => clearTimeout(timer); }, [toast]);

  async function refresh() {
    setLoading(true); setError("");
    try {
      const [response, recurringResponse] = await Promise.all([fetch(`/api/households/${householdId}`, { cache: "no-store" }), fetch(`/api/households/${householdId}/recurring`, { cache: "no-store" })]);
      const body = await response.json();
      if (!response.ok) throw new Error(body.error ?? "Unable to load household");
      const recurringBody = recurringResponse.ok ? await recurringResponse.json() : { recurring: [] };
      setData({ ...body, recurring: recurringBody.recurring }); localStorage.setItem("fairshare-household", householdId);
    } catch (cause) { setError(cause instanceof Error ? cause.message : "Unable to load household"); }
    finally { setLoading(false); }
  }

  async function mutate(path: string, method: string, body?: unknown) {
    if (!session) throw new Error("Session is unavailable");
    const response = await fetch(path, { method, headers: { "content-type": "application/json", "x-csrf-token": session.csrfToken }, body: body === undefined ? undefined : JSON.stringify(body) });
    const result = await response.json();
    if (!response.ok) throw new Error(result.error ?? "Request failed");
    return result;
  }

  async function chooseTheme(next: Theme) {
    const previous = theme; setTheme(next); document.documentElement.dataset.theme = next;
    try { await mutate("/api/settings", "PATCH", { themePreference: next }); }
    catch (cause) { setTheme(previous); document.documentElement.dataset.theme = previous; setToast(cause instanceof Error ? cause.message : "Theme could not be saved"); }
  }

  async function openNotifications() {
    setNotificationsOpen((value) => !value);
    const response = await fetch("/api/notifications", { cache: "no-store" });
    if (response.ok) {
      const items = (await response.json()).notifications as NotificationItem[];
      setNotifications(items);
      if (items.some((item) => !item.readAt)) {
        await mutate("/api/notifications", "PATCH");
        setNotifications(items.map((item) => ({ ...item, readAt: item.readAt ?? new Date().toISOString() })));
      }
    }
  }

  async function openBill(billId: string) {
    const response = await fetch(`/api/households/${householdId}/bills/${billId}`, { cache: "no-store" });
    const body = await response.json();
    if (!response.ok) { setToast(body.error ?? "Bill detail could not be loaded"); return; }
    setBillDetail(body); setModal("detail");
  }

  function openPayment(context: (Balance & { billId: string }) | null = null) { setPaymentContext(context); setModal("payment"); }

  async function logout() {
    try { await mutate("/api/auth/logout", "POST"); } finally { location.href = "/login"; }
  }

  async function install() {
    if (installPrompt && "prompt" in installPrompt) await (installPrompt as Event & { prompt: () => Promise<void> }).prompt();
    else setToast("Use your browser menu to install FairShare on this device.");
  }

  async function enablePush() {
    if (!vapidPublicKey || !("serviceWorker" in navigator) || !("PushManager" in window)) throw new Error("Web Push is not configured on this server");
    const permission = await Notification.requestPermission();
    if (permission !== "granted") throw new Error("Notification permission was not granted");
    const registration = await navigator.serviceWorker.ready;
    const padding = "=".repeat((4 - vapidPublicKey.length % 4) % 4);
    const bytes = Uint8Array.from(atob((vapidPublicKey + padding).replace(/-/g, "+").replace(/_/g, "/")), (character) => character.charCodeAt(0));
    const subscription = await registration.pushManager.subscribe({ userVisibleOnly: true, applicationServerKey: bytes });
    await mutate("/api/settings/push", "POST", subscription.toJSON());
    setToast("Push notifications are enabled on this device.");
  }

  const myBalances = useMemo(() => data?.balances.filter((item) => item.payerUserId === session?.user.id || item.recipientUserId === session?.user.id) ?? [], [data, session]);
  const net = myBalances.reduce((sum, item) => sum + (item.recipientUserId === session?.user.id ? item.amountCents : -item.amountCents), 0);
  const title = tab === "overview" ? `Hello, ${session?.user.displayName.split(" ")[0] ?? "there"}` : tab[0].toUpperCase() + tab.slice(1);

  if (loading && !session) return <main className="loading-screen"><span className="brand-mark"><span className="roof" /><span className="door" /></span><p>Loading FairShare…</p></main>;
  if (session && !session.households.length) return <EmptyAccount user={session.user} onLogout={logout} />;

  return <div className="app-shell">
    <aside className={`sidebar ${sidebarOpen ? "open" : ""}`}>
      <div className="brand"><span className="brand-mark"><span className="roof" /><span className="door" /></span><span>FairShare</span></div>
      <label className="household-switcher"><span className="house-avatar">{initials(data?.household.name ?? "House")}</span><span><small>Household</small><strong>{data?.household.name ?? "Loading…"}</strong></span>
        <select aria-label="Choose household" value={householdId} onChange={(e) => setHouseholdId(e.target.value)}>{session?.households.map((household) => <option key={household.id} value={household.id}>{household.name}</option>)}</select>
      </label>
      <nav className="side-nav">{(["overview", "bills", "upcoming", "balances", "activity"] as Tab[]).map((item) => <button key={item} className={tab === item ? "active" : ""} onClick={() => { setTab(item); setSidebarOpen(false); }}>{item === "overview" ? <LayoutDashboard size={19} /> : item === "bills" ? <ReceiptText size={19} /> : item === "upcoming" ? <CalendarClock size={19} /> : item === "balances" ? <WalletCards size={19} /> : <FileText size={19} />}<span>{item[0].toUpperCase() + item.slice(1)}</span></button>)}</nav>
      <div className="side-bottom"><button className="side-link" onClick={() => setModal("settings")}><Settings size={19} /> User settings</button><button className="profile-card" onClick={() => setModal("settings")}><Avatar name={session?.user.displayName ?? ""} /><span><strong>{session?.user.displayName}</strong><small>{session?.user.email}</small></span></button></div>
    </aside>
    {sidebarOpen && <button className="scrim" aria-label="Close menu" onClick={() => setSidebarOpen(false)} />}
    <main className="main"><header className="topbar"><button className="icon-button menu-button" onClick={() => setSidebarOpen(true)} aria-label="Open menu"><Menu size={22} /></button><div className="top-actions"><button className="install-pill" onClick={install}><ArrowDownLeft size={16} /> Install app</button><button className="icon-button notification-button" onClick={openNotifications} aria-label="Notifications"><Bell size={20} />{notifications.some((item) => !item.readAt) && <span className="unread-dot" />}</button><Avatar name={session?.user.displayName ?? ""} /></div>
      {notificationsOpen && <div className="notification-panel"><div className="panel-title"><strong>Notifications</strong><span>{notifications.filter((item) => !item.readAt).length} new</span></div>{notifications.length ? notifications.slice(0, 8).map((item) => <button key={item.id}><span className="activity-icon mint"><Bell size={17} /></span><span><strong>{item.title}</strong><small>{item.body}</small></span></button>) : <p className="panel-empty">You’re all caught up.</p>}</div>}
    </header>
    <div className="content-wrap"><div className="page-heading"><div><p className="eyebrow">{data?.household.name.toUpperCase()} · {new Date().toLocaleDateString(undefined, { month: "long", year: "numeric" }).toUpperCase()}</p><div className="page-title-row"><h1>{title}</h1>{tab === "overview" && <button className="activity-link-button" onClick={() => setTab("activity")}><FileText size={16} /> Activity</button>}</div><p>{tab === "overview" ? "Here’s where everyone stands today." : tab === "bills" ? "Outstanding expenses and completed settlement history." : tab === "upcoming" ? "Scheduled household expenses and their next occurrence." : tab === "balances" ? "Open person-to-person obligations after repayments." : "Recent bills, settlements, closures, and payments."}</p></div>{tab !== "overview" && <div className="heading-actions"><button className="secondary-button" disabled={!data?.balances.length} onClick={() => openPayment()}><ArrowRight size={17} /> Record payment</button><button className="primary-button" onClick={() => setModal("bill")}><Plus size={18} /> Add bill</button></div>}</div>
      {error && <div className="error-banner">{error}<button onClick={refresh}>Try again</button></div>}
      {loading ? <div className="wide-card loading-card">Refreshing ledger…</div> : tab === "overview" ? <Overview data={data!} user={session!.user} net={net} onBill={() => setModal("bill")} onPayment={() => openPayment()} onBillDetail={openBill} /> : tab === "bills" ? <Bills data={data!} onBillDetail={openBill} /> : tab === "upcoming" ? <Upcoming data={data!} onEditRecurring={(item) => { setSelectedRecurring(item); setModal("recurring-edit"); }} /> : tab === "balances" ? <Balances data={data!} user={session!.user} onPayment={() => openPayment()} /> : <Activity data={data!} onBillDetail={openBill} />}
    </div></main>
    <nav className="bottom-nav">{(["overview", "bills"] as Tab[]).map((item) => <MobileNav key={item} item={item} tab={tab} setTab={setTab} />)}<button className="fab" onClick={() => setModal("bill")}><Plus size={24} /></button>{(["upcoming", "balances"] as Tab[]).map((item) => <MobileNav key={item} item={item} tab={tab} setTab={setTab} />)}</nav>
    {modal === "bill" && data && <BillModal data={data} currentUserId={session?.user.id} close={() => setModal(null)} save={async (body, recurring) => { await mutate(`/api/households/${householdId}/bills`, "POST", { ...(body as object), ...(recurring ? { recurring } : {}) }); setModal(null); setToast(recurring ? "Bill and recurring schedule added." : "Bill added to the household ledger."); await refresh(); }} />}
    {modal === "edit" && data && billDetail && <BillModal data={data} currentUserId={session?.user.id} initial={billDetail} close={() => setModal("detail")} save={async (body) => { await mutate(`/api/households/${householdId}/bills/${billDetail.bill.id}`, "PATCH", body); setModal(null); setToast("Bill updated and balances recalculated."); await refresh(); }} />}
    {modal === "payment" && data && <PaymentModal data={data} specific={paymentContext} close={() => { setModal(null); setPaymentContext(null); }} save={async (body) => { await mutate(`/api/households/${householdId}/payments`, "POST", body); setModal(null); setPaymentContext(null); setToast("Payment recorded."); await refresh(); }} />}
    {modal === "recurring-edit" && data && selectedRecurring && <RecurringModal data={data} initial={selectedRecurring} close={() => setModal(null)} save={async (body) => { await mutate(`/api/households/${householdId}/recurring/${selectedRecurring.id}`, "PATCH", body); setModal(null); setSelectedRecurring(null); setToast("Future recurring bills will use the updated schedule."); await refresh(); }} />}
    {modal === "settings" && session && <SettingsModal session={session} theme={theme} preferences={preferences} pushAvailable={Boolean(vapidPublicKey)} chooseTheme={chooseTheme} updatePreferences={async (next) => { await mutate("/api/settings", "PATCH", { notifications: next }); setPreferences(next); }} enablePush={enablePush} changePassword={async (currentPassword, newPassword) => { await mutate("/api/settings/password", "POST", { currentPassword, newPassword }); location.href = "/login"; }} close={() => setModal(null)} logout={logout} />}
    {modal === "detail" && billDetail && <BillDetailModal detail={billDetail} userId={session?.user.id ?? ""} currency={data?.household.currency ?? "USD"} close={() => setModal(null)} edit={() => setModal("edit")} remove={async () => { if (!confirm("Remove this bill and recalculate Household balances? The audit record is retained.")) return; try { await mutate(`/api/households/${householdId}/bills/${billDetail.bill.id}`, "DELETE"); setModal(null); setToast("Bill removed and balances recalculated."); await refresh(); } catch (cause) { setToast(cause instanceof Error ? cause.message : "Bill could not be removed"); } }} record={(item) => openPayment({ billId: billDetail.bill.id, payerUserId: item.debtorUserId, recipientUserId: item.creditorUserId, payerName: item.debtorName, recipientName: item.creditorName, amountCents: item.outstandingAmountCents })} settle={async (item) => { if (!confirm(`Record ${money(item.outstandingAmountCents, data?.household.currency ?? "USD")} from ${item.debtorName} to ${item.creditorName} and mark this share settled?`)) return; try { await mutate(`/api/households/${householdId}/payments`, "POST", { billId: billDetail.bill.id, payerUserId: item.debtorUserId, recipientUserId: item.creditorUserId, amountCents: item.outstandingAmountCents, note: "Marked settled", paidAt: new Date().toISOString() }); setToast(`${item.debtorName}’s share was settled.`); await refresh(); await openBill(billDetail.bill.id); } catch (cause) { setToast(cause instanceof Error ? cause.message : "Share could not be settled"); } }} closeWithoutPayment={async () => { if (!confirm("Close this entire expense without recording payments? Use this only when settlement was recorded separately.")) return; try { await mutate(`/api/households/${householdId}/bills/${billDetail.bill.id}/close`, "POST"); setModal(null); setToast("Expense closed without recording another payment."); await refresh(); } catch (cause) { setToast(cause instanceof Error ? cause.message : "Expense could not be closed"); } }} />}
    {toast && <div className="toast"><span><Check size={16} /></span>{toast}</div>}
  </div>;
}

function Avatar({ name }: { name: string }) { return <span className="avatar mint small" aria-label={name}>{initials(name)}</span>; }
function MobileNav({ item, tab, setTab }: { item: Tab; tab: Tab; setTab: (value: Tab) => void }) { const Icon = item === "overview" ? LayoutDashboard : item === "bills" ? ReceiptText : item === "upcoming" ? CalendarClock : item === "balances" ? WalletCards : FileText; return <button className={tab === item ? "active" : ""} onClick={() => setTab(item)}><Icon size={21} /><small>{item === "overview" ? "Home" : item[0].toUpperCase() + item.slice(1)}</small></button>; }

function Overview({ data, user, net, onBill, onPayment, onBillDetail }: { data: HouseholdData; user: User; net: number; onBill: () => void; onPayment: () => void; onBillDetail: (id: string) => void }) {
  return <div className="dashboard-grid"><section className="summary-card"><div className="summary-top"><span className="summary-icon"><WalletCards size={21} /></span><span>Your overall position</span></div><p>{net < 0 ? "You owe" : "You are owed"}</p><h2>{money(Math.abs(net), data.household.currency)}</h2><span className="delta">Across {data.balances.length} open balance{data.balances.length === 1 ? "" : "s"}</span><div className="summary-divider" />{data.balances.filter((item) => item.payerUserId === user.id || item.recipientUserId === user.id).slice(0, 3).map((item) => <div className="mini-balance" key={`${item.payerUserId}:${item.recipientUserId}`}><div className="avatar-pair"><Avatar name={item.payerName ?? ""} /><Avatar name={item.recipientName ?? ""} /></div><span><small>{item.payerUserId === user.id ? `You owe ${item.recipientName}` : `${item.payerName} owes you`}</small><strong>{money(item.amountCents, data.household.currency)}</strong></span></div>)}</section>
    <section className="card recent-card"><div className="section-heading"><div><p className="eyebrow">RECENT BILLS</p><h3>Latest household expenses</h3></div><span className="count-badge">{data.bills.length}</span></div><div className="bill-list">{data.bills.slice(0, 5).map((bill) => <BillRow key={bill.id} bill={bill} currency={data.household.currency} onClick={() => onBillDetail(bill.id)} />)}{!data.bills.length && <p className="empty-copy">No bills yet. Add the first shared expense.</p>}</div></section>
    <section className="quick-card"><div><span className="quick-icon"><CreditCard size={22} /></span><span><strong>Keep the ledger current</strong><small>Add an expense or settle an open balance.</small></span></div><div><button className="quick-action" onClick={onBill}><Plus size={18} /><span><strong>Add a bill</strong><small>Split an expense</small></span></button><button className="quick-action" onClick={onPayment} disabled={!data.balances.length}><CreditCard size={18} /><span><strong>Record payment</strong><small>Settle a balance</small></span></button></div></section></div>;
}

function BillRow({ bill, currency, onClick }: { bill: Bill; currency: string; onClick?: () => void }) { const settled = bill.status === "settled"; return <button className="bill-row" onClick={onClick}><span className={`activity-icon ${settled ? "mint" : "coral"}`}>{settled ? <Check size={18} /> : <ReceiptText size={18} />}</span><span className="bill-main"><strong>{bill.name}</strong><small>{bill.periodLabel} · {bill.amountState}</small></span><span className="bill-amount"><strong>{money(bill.amountCents, currency)}</strong><span className={`status-pill ${settled ? "done" : "open"}`}>{settled ? "Settled" : "Outstanding"}</span></span></button>; }
function Bills({ data, onBillDetail }: { data: HouseholdData; onBillDetail: (id: string) => void }) { const [filter, setFilter] = useState<"open" | "settled">("open"); const bills = data.bills.filter((bill) => bill.status === filter); const openCount = data.bills.filter((bill) => bill.status === "open").length; const settledCount = data.bills.filter((bill) => bill.status === "settled").length; return <div className="balances-layout"><section className="wide-card"><div className="section-heading bills-heading"><div><h3>{filter === "open" ? "Outstanding expenses" : "Settled expenses"}</h3><p>{filter === "open" ? "Select an expense to settle each person’s share." : "Completed expenses remain available for review."}</p></div><div className="filter-pills bill-status-filter"><button className={filter === "open" ? "selected" : ""} onClick={() => setFilter("open")}>Outstanding · {openCount}</button><button className={filter === "settled" ? "selected" : ""} onClick={() => setFilter("settled")}>Settled · {settledCount}</button></div></div><div className="month-total"><span><small>OUTSTANDING</small><strong>{openCount}</strong></span><span><small>SETTLED</small><strong>{settledCount}</strong></span><span><small>RECORDED SPEND</small><strong>{money(data.bills.reduce((sum, bill) => sum + bill.amountCents, 0), data.household.currency)}</strong></span><span><small>OPEN BALANCES</small><strong>{money(data.balances.reduce((sum, item) => sum + item.amountCents, 0), data.household.currency)}</strong></span></div><div className="bill-list">{bills.map((bill) => <BillRow key={bill.id} bill={bill} currency={data.household.currency} onClick={() => onBillDetail(bill.id)} />)}{!bills.length && <p className="empty-copy">{filter === "open" ? "No outstanding expenses. Everyone is settled up." : "No settled expenses yet."}</p>}</div></section></div>; }
function Upcoming({ data, onEditRecurring }: { data: HouseholdData; onEditRecurring: (item: Recurring) => void }) { const schedules = [...data.recurring].sort((a, b) => +new Date(a.nextOccurrence) - +new Date(b.nextOccurrence)); return <section className="wide-card upcoming-view"><div className="section-heading"><div><h3>Upcoming and scheduled bills</h3><p>Select a schedule to edit its future amount, cadence, or next date.</p></div><span className="count-badge">{schedules.filter((item) => item.active).length}</span></div><div className="upcoming-list">{schedules.map((item) => { const date = new Date(item.nextOccurrence); return <button className="calendar-item scheduled-item" key={item.id} onClick={() => onEditRecurring(item)}><span className="date-tile"><b>{date.getDate()}</b><small>{date.toLocaleDateString(undefined, { month: "short" }).toUpperCase()}</small></span><span><strong>{item.name}</strong><small>{item.cadence} · {item.expectedAmountCents === null ? "variable amount" : money(item.expectedAmountCents, data.household.currency)}</small></span><span className={`status-pill ${item.active ? "done" : "open"}`}>{item.active ? "Scheduled" : "Paused"}</span></button>; })}{!schedules.length && <p className="empty-copy">No scheduled bills yet. Enable recurrence while adding an expense.</p>}</div></section>; }
function Balances({ data, user, onPayment }: { data: HouseholdData; user: User; onPayment: () => void }) { return <div className="balances-layout"><section className="wide-card"><div className="section-heading"><div><h3>Household balances</h3><p>Payments reduce these balances without altering original bills.</p></div></div><div className="balance-lines">{data.balances.map((item) => <div key={`${item.payerUserId}:${item.recipientUserId}`}><div className="avatar-pair large"><Avatar name={item.payerName ?? ""} /><Avatar name={item.recipientName ?? ""} /></div><span><strong>{item.payerUserId === user.id ? `You owe ${item.recipientName}` : item.recipientUserId === user.id ? `${item.payerName} owes you` : `${item.payerName} owes ${item.recipientName}`}</strong><small>Outstanding household balance</small></span><strong>{money(item.amountCents, data.household.currency)}</strong><button className="secondary-button" onClick={onPayment}>Record</button></div>)}{!data.balances.length && <p className="empty-copy">Everyone is settled up.</p>}</div></section></div>; }
function Activity({ data, onBillDetail }: { data: HouseholdData; onBillDetail: (id: string) => void }) { const items = [...data.bills.map((bill) => ({ id: `bill:${bill.id}`, billId: bill.id, when: bill.createdAt, title: `${bill.name} added`, detail: `${money(bill.amountCents, data.household.currency)} · ${bill.status === "settled" ? "Settled" : "Outstanding"} · Added by ${bill.createdByName ?? "a household member"}`, kind: "bill" as const })), ...data.payments.map((payment) => ({ id: `payment:${payment.id}`, billId: payment.billId ?? undefined, when: payment.paidAt, title: payment.note === "Marked settled" && payment.billName ? `${payment.payerName} settled their share of ${payment.billName}` : payment.billName ? `${payment.payerName} paid toward ${payment.billName}` : `${payment.payerName ?? "A member"} recorded a general payment`, detail: `${money(payment.amountCents, data.household.currency)} to ${payment.recipientName ?? "another member"} · Recorded by ${payment.actorName ?? "a household member"}`, kind: "payment" as const })), ...data.closures.map((closure) => ({ id: `closure:${closure.id}`, billId: closure.billId, when: closure.changedAt, title: `${closure.billName} closed without another payment`, detail: `Closed by ${closure.actorName}`, kind: "closure" as const }))].sort((a, b) => +new Date(b.when) - +new Date(a.when)); return <section className="wide-card activity-view"><div className="timeline">{items.map((item) => <div className="timeline-group" key={item.id}><button className="timeline-item" disabled={!item.billId} onClick={() => item.billId && onBillDetail(item.billId)}><span className={`activity-icon ${item.kind === "bill" ? "coral" : item.kind === "closure" ? "yellow" : "mint"}`}>{item.kind === "bill" ? <ReceiptText size={18} /> : item.kind === "closure" ? <Check size={18} /> : <CreditCard size={18} />}</span><span><strong>{item.title}</strong><small>{item.detail}</small></span><time>{new Date(item.when).toLocaleDateString()}</time></button></div>)}{!items.length && <p className="empty-copy">Activity will appear here as bills, settlements, closures, and payments are recorded.</p>}</div></section>; }

function Modal({ title, subtitle, close, children }: { title: string; subtitle: string; close: () => void; children: React.ReactNode }) { return <div className="modal-backdrop" onMouseDown={(event) => { if (event.target === event.currentTarget) close(); }}><section className="modal" role="dialog" aria-modal="true"><div className="modal-header"><div><h2>{title}</h2><p>{subtitle}</p></div><button className="icon-button" onClick={close}><X size={20} /></button></div><div className="modal-body">{children}</div></section></div>; }

function BillModal({ data, currentUserId, initial, close, save }: { data: HouseholdData; currentUserId?: string; initial?: BillDetailData; close: () => void; save: (body: unknown, recurring?: unknown) => Promise<void> }) {
  const initialAllocations = Object.fromEntries((initial?.allocations ?? []).map((item) => [item.userId, initial?.bill.allocationMethod === "percentage" ? String((item.percentageBasisPoints ?? 0) / 100) : (item.amountCents / 100).toFixed(2)]));
  const defaultPayer = initial?.contributions[0]?.userId ?? data.members.find((member) => member.id === currentUserId)?.id ?? data.members[0]?.id ?? "";
  const [name, setName] = useState(initial?.bill.name ?? ""); const [amount, setAmount] = useState(initial ? (initial.bill.amountCents / 100).toFixed(2) : ""); const [estimated, setEstimated] = useState(initial?.bill.amountState === "estimated"); const [method, setMethod] = useState<"equal" | "percentage" | "fixed">((initial?.bill.allocationMethod as "equal" | "percentage" | "fixed") ?? "equal"); const [payerId, setPayerId] = useState(defaultPayer); const [allocationValues, setAllocationValues] = useState<Record<string, string>>(initialAllocations); const [makeRecurring, setMakeRecurring] = useState(false); const [cadence, setCadence] = useState<Recurring["cadence"]>("monthly"); const [nextDate, setNextDate] = useState(""); const [busy, setBusy] = useState(false); const [error, setError] = useState("");
  async function submit(event: React.FormEvent) {
    event.preventDefault(); const amountCents = Math.round(Number(amount) * 100); if (!amountCents) return;
    if (!payerId) { setError("Choose who paid the bill"); return; }
    const contributions = [{ userId: payerId, amountCents }];
    let allocations: Array<{ userId: string; amountCents: number; percentageBasisPoints?: number }>;
    if (method === "equal") { const base = Math.floor(amountCents / data.members.length); let remainder = amountCents - base * data.members.length; allocations = data.members.map((member) => ({ userId: member.id, amountCents: base + (remainder-- > 0 ? 1 : 0) })); }
    else if (method === "fixed") allocations = data.members.map((member) => ({ userId: member.id, amountCents: Math.round(Number(allocationValues[member.id] || 0) * 100) })).filter((item) => item.amountCents > 0);
    else { const basis = data.members.map((member) => ({ userId: member.id, percentageBasisPoints: Math.round(Number(allocationValues[member.id] || 0) * 100) })); let allocated = 0; allocations = basis.map((item, index) => { const amountForMember = index === basis.length - 1 ? amountCents - allocated : Math.floor(amountCents * item.percentageBasisPoints / 10_000); allocated += amountForMember; return { ...item, amountCents: amountForMember }; }).filter((item) => item.amountCents > 0 || item.percentageBasisPoints > 0); }
    if (makeRecurring && !nextDate) { setError("Choose the next occurrence date"); return; }
    const body = { name, amountCents, periodLabel: initial?.bill.periodLabel ?? new Date().toLocaleDateString(undefined, { month: "long", year: "numeric" }), dueDate: initial?.bill.dueDate ?? null, amountState: estimated ? "estimated" : "final", allocationMethod: method, contributions, allocations, ...(initial ? { revision: initial.bill.revision } : {}) };
    const recurring = makeRecurring ? { name, expectedAmountCents: amountCents, cadence, nextOccurrence: new Date(`${nextDate}T12:00:00Z`).toISOString(), allocationMethod: method, contributions, allocations, active: true } : undefined;
    setBusy(true); setError(""); try { await save(body, recurring); } catch (cause) { setError(cause instanceof Error ? cause.message : "Unable to save bill"); setBusy(false); }
  }
  const allocationTotal = data.members.reduce((sum, member) => sum + Number(allocationValues[member.id] || 0), 0);
  const allocationTarget = method === "percentage" ? 100 : Number(amount || 0);
  const allocationRemaining = allocationTarget - allocationTotal;
  const allocationComplete = method === "equal" || Math.abs(allocationRemaining) < .001;
  const allocationProgress = method === "percentage"
    ? `${Math.abs(allocationRemaining).toFixed(2)}% ${allocationRemaining < 0 ? "over" : "remaining"}`
    : `${money(Math.round(Math.abs(allocationRemaining) * 100), data.household.currency)} ${allocationRemaining < 0 ? "over" : "remaining"}`;
  return <Modal title={initial ? "Edit bill" : "Add a bill"} subtitle={data.household.name} close={close}><form onSubmit={submit}><div className="form-grid"><label className="full">Bill name<input value={name} onChange={(e) => setName(e.target.value)} required autoFocus /></label><label>Amount ({data.household.currency})<input type="number" inputMode="decimal" min="0.01" max="1000000000" step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} required /></label><label className="toggle-row"><span><strong>Estimated amount</strong><small>Finalize it later with a revision.</small></span><input type="checkbox" checked={estimated} onChange={(e) => setEstimated(e.target.checked)} /></label><fieldset className="full"><legend>Who paid the external bill?</legend><div className="payer-options">{data.members.map((member) => <label key={member.id} className={`payer-option ${payerId === member.id ? "selected" : ""}`}><input type="checkbox" checked={payerId === member.id} onChange={() => setPayerId(member.id)} /><Avatar name={member.displayName} /><span><strong>{member.displayName}</strong><small>Paid the full {amount ? money(Math.round(Number(amount) * 100), data.household.currency) : "bill"}</small></span></label>)}</div><small className="valid-total">Choose one person. The full expense is credited to them.</small></fieldset><fieldset className="full"><legend>How is responsibility allocated?</legend><div className="segmented">{(["equal", "percentage", "fixed"] as const).map((item) => <button type="button" key={item} className={method === item ? "selected" : ""} onClick={() => setMethod(item)}>{item === "percentage" ? "Percent" : item[0].toUpperCase() + item.slice(1)}</button>)}</div>{method !== "equal" && <div className="money-rows">{data.members.map((member) => <label key={member.id}><span>{member.displayName}</span><span className="amount-field"><input aria-label={`${member.displayName} ${method === "percentage" ? "percentage" : "amount"}`} type="number" inputMode="decimal" min="0" step=".01" placeholder="0" value={allocationValues[member.id] ?? ""} onChange={(e) => setAllocationValues({ ...allocationValues, [member.id]: e.target.value })} /><em>{method === "percentage" ? "%" : data.household.currency}</em></span></label>)}</div>}<small className={allocationComplete ? "valid-total" : "invalid-total"}>{method === "equal" ? `Split equally across ${data.members.length} members` : allocationProgress}</small></fieldset>{!initial && <><label className="toggle-row full recurring-toggle"><span><strong>Make this expense recurring</strong><small>Create future bills automatically using this payer and allocation.</small></span><input type="checkbox" checked={makeRecurring} onChange={(e) => setMakeRecurring(e.target.checked)} /></label>{makeRecurring && <div className="recurring-details full"><label>Cadence<select value={cadence} onChange={(e) => setCadence(e.target.value as Recurring["cadence"])}><option value="weekly">Weekly</option><option value="monthly">Monthly</option><option value="quarterly">Quarterly</option><option value="yearly">Yearly</option></select></label><label>Next occurrence<input type="date" value={nextDate} onChange={(e) => setNextDate(e.target.value)} required /></label></div>}</>}</div>{error && <p className="form-error">{error}</p>}<div className="modal-actions"><button type="button" className="secondary-button" onClick={close}>Cancel</button><button className="primary-button" disabled={busy || !name || !amount || !payerId}>{busy ? "Saving…" : initial ? "Save changes" : makeRecurring ? "Add recurring bill" : "Add bill"}</button></div></form></Modal>;
}

function PaymentModal({ data, specific, close, save }: { data: HouseholdData; specific: (Balance & { billId: string }) | null; close: () => void; save: (body: unknown) => Promise<void> }) {
  const choices = specific ? [specific] : data.balances; const [index, setIndex] = useState(0); const [amount, setAmount] = useState(""); const [note, setNote] = useState(""); const [busy, setBusy] = useState(false); const [error, setError] = useState(""); const balance = choices[index];
  async function submit(event: React.FormEvent) { event.preventDefault(); if (!balance) return; setBusy(true); setError(""); try { await save({ billId: specific?.billId ?? null, payerUserId: balance.payerUserId, recipientUserId: balance.recipientUserId, amountCents: Math.round(Number(amount) * 100), note, paidAt: new Date().toISOString() }); } catch (cause) { setError(cause instanceof Error ? cause.message : "Unable to record payment"); setBusy(false); } }
  return <Modal title="Record a payment" subtitle={specific ? "Apply this payment to one bill" : "Reduce the general running balance"} close={close}>{balance ? <form onSubmit={submit}><div className="form-grid"><label className="full">Balance<select value={index} disabled={Boolean(specific)} onChange={(e) => { setIndex(Number(e.target.value)); setAmount(""); }}>{choices.map((item, itemIndex) => <option key={`${item.payerUserId}:${item.recipientUserId}`} value={itemIndex}>{item.payerName} → {item.recipientName} · {money(item.amountCents, data.household.currency)}</option>)}</select></label><label className="full">Amount<input type="number" inputMode="decimal" min="0.01" max={(balance.amountCents / 100).toFixed(2)} step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} required /></label><label className="full">Note (optional)<input value={note} onChange={(e) => setNote(e.target.value)} maxLength={500} /></label></div>{error && <p className="form-error">{error}</p>}<div className="modal-actions"><button type="button" className="secondary-button" onClick={close}>Cancel</button><button className="primary-button" disabled={busy || !amount}>{busy ? "Recording…" : "Record payment"}</button></div></form> : <p>There are no open balances to pay.</p>}</Modal>;
}

function BillDetailModal({ detail, userId, currency, close, edit, remove, record, settle, closeWithoutPayment }: { detail: BillDetailData; userId: string; currency: string; close: () => void; edit: () => void; remove: () => Promise<void>; record: (item: BillDetailData["obligations"][number]) => void; settle: (item: BillDetailData["obligations"][number]) => Promise<void>; closeWithoutPayment: () => Promise<void> }) { const isSettled = detail.bill.status === "settled"; return <Modal title={detail.bill.name} subtitle={`${detail.bill.periodLabel} · ${detail.bill.amountState} · revision ${detail.bill.revision}`} close={close}><div className="detail-status-row"><p className="detail-total">{money(detail.bill.amountCents, currency)}</p><span className={`status-pill ${isSettled ? "done" : "open"}`}>{isSettled ? "Settled" : "Outstanding"}</span></div><div className="detail-section"><h3>Paid to the external recipient</h3>{detail.contributions.map((item) => <div className="contribution" key={item.id}><Avatar name={item.displayName} /><span><strong>{item.displayName}</strong><small>{new Date(item.paidAt).toLocaleDateString()}</small></span><strong>{money(item.amountCents, currency)}</strong></div>)}</div><div className="detail-section"><h3>{detail.bill.allocationMethod} allocation</h3>{detail.allocations.map((item) => <div className="contribution" key={item.id}><Avatar name={item.displayName} /><span><strong>{item.displayName}</strong><small>{item.percentageBasisPoints === null ? "Responsibility" : `${item.percentageBasisPoints / 100}%`}</small></span><strong>{money(item.amountCents, currency)}</strong></div>)}</div><div className="detail-section"><h3>Settlement by person</h3>{detail.obligations.map((item) => { const involved = item.debtorUserId === userId || item.creditorUserId === userId; const paid = item.outstandingAmountCents === 0; return <div className="obligation" key={item.id}><div className="avatar-pair"><Avatar name={item.debtorName} /><Avatar name={item.creditorName} /></div><span><strong>{item.debtorName} → {item.creditorName}</strong><small>{money(item.paidAmountCents, currency)} paid of {money(item.originalAmountCents, currency)}</small></span><strong>{money(item.outstandingAmountCents, currency)}</strong>{paid ? <span className="status-pill done">Settled</span> : isSettled ? <span className="status-pill done">Closed</span> : involved ? <span className="obligation-actions"><button className="partial-button" onClick={() => record(item)}>Partial</button><button onClick={() => settle(item)}>Settle</button></span> : <span className="status-pill open">Outstanding</span>}</div>; })}{!detail.obligations.length && <p className="empty-copy">No repayments are required for this expense.</p>}</div><div className="detail-section audit"><h3>Bill history</h3>{detail.history.map((item) => <div key={item.id}><span className="history-dot" /><span><strong>{item.changeType.replaceAll("_", " ")}</strong><small>{item.changedBy} · {new Date(item.changedAt).toLocaleString()}</small></span></div>)}</div><div className="modal-actions bill-detail-actions"><button className="secondary-button danger-button" onClick={remove}>Remove</button>{!isSettled && <button className="secondary-button close-expense-button" onClick={closeWithoutPayment}>Close without payment</button>}{!isSettled && <button className="secondary-button" onClick={edit}>Edit terms</button>}<button className="primary-button" onClick={close}>Done</button></div></Modal>; }

function RecurringModal({ data, initial, close, save }: { data: HouseholdData; initial: Recurring; close: () => void; save: (body: unknown) => Promise<void> }) {
  const [name, setName] = useState(initial.name); const [amount, setAmount] = useState(initial.expectedAmountCents ? (initial.expectedAmountCents / 100).toFixed(2) : ""); const [payer] = useState(initial.templateConfig.contributions[0]?.userId ?? data.members[0]?.id ?? ""); const [cadence, setCadence] = useState<Recurring["cadence"]>(initial.cadence); const [nextDate, setNextDate] = useState(new Date(initial.nextOccurrence).toISOString().slice(0, 10)); const [active, setActive] = useState(initial.active); const [busy, setBusy] = useState(false); const [error, setError] = useState("");
  async function submit(event: React.FormEvent) { event.preventDefault(); const amountCents = Math.round(Number(amount) * 100); let contributions = initial.templateConfig.contributions; let allocations = initial.templateConfig.allocations; let allocationMethod = initial.allocationMethod; if (initial.expectedAmountCents !== amountCents) { const base = Math.floor(amountCents / data.members.length); let remainder = amountCents - base * data.members.length; contributions = [{ userId: payer, amountCents }]; allocations = data.members.map((member) => ({ userId: member.id, amountCents: base + (remainder-- > 0 ? 1 : 0) })); allocationMethod = "equal"; } setBusy(true); setError(""); try { await save({ name, expectedAmountCents: amountCents, cadence, nextOccurrence: new Date(`${nextDate}T12:00:00Z`).toISOString(), allocationMethod, contributions, allocations, active }); } catch (cause) { setError(cause instanceof Error ? cause.message : "Unable to save schedule"); setBusy(false); } }
  return <Modal title="Edit future schedule" subtitle="Historical bill instances will not change" close={close}><form onSubmit={submit}><div className="form-grid"><label className="full">Bill name<input value={name} onChange={(e) => setName(e.target.value)} required autoFocus /></label><label>Expected amount ({data.household.currency})<input type="number" inputMode="decimal" min="0.01" step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} required /></label><label>Paid externally by<select value={payer} disabled>{data.members.map((member) => <option key={member.id} value={member.id}>{member.displayName}</option>)}</select></label><label>Cadence<select value={cadence} onChange={(e) => setCadence(e.target.value as Recurring["cadence"])}><option value="weekly">Weekly</option><option value="monthly">Monthly</option><option value="quarterly">Quarterly</option><option value="yearly">Yearly</option></select></label><label>Next occurrence<input type="date" value={nextDate} onChange={(e) => setNextDate(e.target.value)} required /></label><label className="toggle-row"><span><strong>Schedule active</strong><small>Pause future generation without changing history.</small></span><input type="checkbox" checked={active} onChange={(e) => setActive(e.target.checked)} /></label></div>{error && <p className="form-error">{error}</p>}<div className="modal-actions"><button type="button" className="secondary-button" onClick={close}>Cancel</button><button className="primary-button" disabled={busy || !name || !amount || !payer || !nextDate}>{busy ? "Saving…" : "Save future schedule"}</button></div></form></Modal>;
}

function SettingsModal({ session, theme, preferences, pushAvailable, chooseTheme, updatePreferences, enablePush, changePassword, close, logout }: { session: SessionData; theme: Theme; preferences: NotificationPrefs; pushAvailable: boolean; chooseTheme: (theme: Theme) => Promise<void>; updatePreferences: (next: NotificationPrefs) => Promise<void>; enablePush: () => Promise<void>; changePassword: (current: string, next: string) => Promise<void>; close: () => void; logout: () => Promise<void> }) { const [currentPassword, setCurrentPassword] = useState(""); const [newPassword, setNewPassword] = useState(""); const [error, setError] = useState(""); async function toggle(key: keyof NotificationPrefs) { const next = { ...preferences, [key]: !preferences[key] }; try { await updatePreferences(next); } catch (cause) { setError(cause instanceof Error ? cause.message : "Preferences could not be saved"); } } async function passwordSubmit(event: React.FormEvent) { event.preventDefault(); setError(""); try { await changePassword(currentPassword, newPassword); } catch (cause) { setError(cause instanceof Error ? cause.message : "Password could not be changed"); } } async function push() { setError(""); try { await enablePush(); } catch (cause) { setError(cause instanceof Error ? cause.message : "Push could not be enabled"); } } return <Modal title="User settings" subtitle={`Preferences for ${session.user.displayName}`} close={close}><div className="settings-profile"><Avatar name={session.user.displayName} /><span><strong>{session.user.displayName}</strong><small>{session.user.email}</small></span><span className="status-pill done">Active</span></div><section className="preference-section"><div><h3>Appearance</h3><p>Your choice is saved to your account. Neutral Dark is the default.</p></div><div className="theme-options"><button className={theme === "dark" ? "selected" : ""} onClick={() => chooseTheme("dark")}><Moon size={19} /><span><strong>Dark</strong><small>Neutral · default</small></span>{theme === "dark" && <Check size={16} />}</button><button className={theme === "forest" ? "selected" : ""} onClick={() => chooseTheme("forest")}><Trees size={19} /><span><strong>Forest Green</strong><small>Original palette</small></span>{theme === "forest" && <Check size={16} />}</button><button className={theme === "light" ? "selected" : ""} onClick={() => chooseTheme("light")}><Sun size={19} /><span><strong>Light</strong><small>Bright surfaces</small></span>{theme === "light" && <Check size={16} />}</button></div></section><section className="preference-section"><div><h3>Notifications</h3><p>Choose which Household events create in-app and push notifications.</p></div><div className="notification-preferences"><label><span><strong>Bills and material edits</strong><small>New, edited, finalized, and recurring bills</small></span><input type="checkbox" checked={preferences.billsEnabled} onChange={() => toggle("billsEnabled")} /></label><label><span><strong>Payments involving you</strong><small>Bill-specific and general repayments</small></span><input type="checkbox" checked={preferences.paymentsEnabled} onChange={() => toggle("paymentsEnabled")} /></label><label><span><strong>Balance changes</strong><small>Meaningful changes to what you owe or are owed</small></span><input type="checkbox" checked={preferences.balanceChangesEnabled} onChange={() => toggle("balanceChangesEnabled")} /></label></div><button className="secondary-button push-button" disabled={!pushAvailable} onClick={push}>{pushAvailable ? "Enable push on this device" : "Web Push is not configured"}</button></section><section className="preference-section"><div><h3>Change password</h3><p>Changing your password signs out every device, including this one.</p></div><form className="settings-password" onSubmit={passwordSubmit}><input type="password" autoComplete="current-password" placeholder="Current password" value={currentPassword} onChange={(e) => setCurrentPassword(e.target.value)} required /><input type="password" autoComplete="new-password" placeholder="New password (12+ characters)" minLength={12} value={newPassword} onChange={(e) => setNewPassword(e.target.value)} required /><button className="secondary-button">Change password</button></form></section>{error && <p className="form-error">{error}</p>}<div className="modal-actions"><button className="secondary-button" onClick={logout}>Sign out</button><button className="primary-button" onClick={close}>Done</button></div></Modal>; }

function EmptyAccount({ user, onLogout }: { user: User; onLogout: () => Promise<void> }) { return <main className="auth-shell"><section className="auth-card"><div className="auth-brand"><span className="brand-mark"><span className="roof" /><span className="door" /></span><span>FairShare</span></div><span className="setup-icon"><WalletCards size={24} /></span><h1>No Household assigned</h1><p>Hello {user.displayName}. An administrator needs to add your account to a Household before financial data is available.</p><button className="secondary-button" onClick={onLogout}>Sign out</button></section></main>; }
